      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        {TESTIMONIALS.map((testimonial) => (
          <div key={testimonial.id} className="glass p-8 rounded-3xl border border-white/5 flex flex-col justify-between hover:border-pink-500/20 transition-all duration-300 group">
