import React, { useEffect, useRef, useState } from 'react';
import { PROJECTS } from '../constants';

const ProjectCard: React.FC<{ project: any; index: number }> = ({ project, index }) => {
  const [isVisible, setIsVisible] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          observer.unobserve(entry.target);
        }
      },
      { threshold: 0.1 }
    );
    if (cardRef.current) observer.observe(cardRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <div
      ref={cardRef}
      className={`group relative rounded-2xl overflow-hidden glass border border-white/5 transition-all duration-1000 ease-[cubic-bezier(0.23,1,0.32,1)] ${
        isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'
      }`}
      style={{ transitionDelay: `${index * 80}ms` }}
    >
      <div className="aspect-[4/3] w-full overflow-hidden">
        <img 
          src={project.imageUrl} 
          alt={project.title}
          className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-105"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/10 to-transparent" />
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-5">
        <div className="flex flex-wrap gap-1 mb-3">
          {project.tags.map((tag: string) => (
            <span key={tag} className="px-1.5 py-0.5 bg-white/5 backdrop-blur-md rounded text-[8px] font-black uppercase tracking-widest text-white/40 border border-white/5">
              {tag}
            </span>
          ))}
        </div>
        <h4 className="text-base font-bold mb-1 tracking-tight text-white group-hover:text-blue-400 transition-colors">
          {project.title}
        </h4>
        <p className="text-[10px] text-gray-400 line-clamp-1 mb-4 opacity-70 group-hover:opacity-100 transition-opacity">
          {project.description}
        </p>
        <a href={project.link} className="inline-flex items-center space-x-1.5 text-[9px] font-black uppercase tracking-[0.2em] text-white/50 hover:text-white transition-colors">
          <span>Explore</span>
          <svg className="h-2.5 w-2.5" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M12.293 5.293a1 1 0 011.414 0l4 4a1 1 0 010 1.414l-4 4a1 1 0 01-1.414-1.414L14.586 11H3a1 1 0 110-2h11.586l-2.293-2.293a1 1 0 010-1.414z" clipRule="evenodd" />
          </svg>
        </a>
      </div>
    </div>
  );
};

