      { threshold: 0.1 }
    );
    if (cardRef.current) observer.observe(cardRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <div
      ref={cardRef}
      className={`group relative rounded-3xl overflow-hidden glass border border-white/5 transition-all duration-1000 ease-[cubic-bezier(0.23,1,0.32,1)] ${
